      // Internally a reference into a global interned BDD (INTERNER).
      // TRUE  = MarkerTree(NodeId::TRUE)  — always satisfied
      // FALSE = MarkerTree(NodeId::FALSE) — never satisfied (unsatisfiable in any env)
      //
